{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-greeting",
          "role": "assertion",
          "binding": "/greeting"
        },
        {
          "id": "home-today-recommendation",
          "role": "assertion",
          "binding": "/today/recommendation"
        },
        {
          "id": "home-wheel-card",
          "role": "action",
          "event": "navigate-to-wheel"
        },
        {
          "id": "home-pantry-card",
          "role": "action",
          "event": "navigate-to-pantry"
        },
        {
          "id": "home-filter-card",
          "role": "action",
          "event": "navigate-to-filter"
        },
        {
          "id": "home-log-card",
          "role": "action",
          "event": "navigate-to-log"
        },
        {
          "id": "home-tab-bar",
          "role": "tab-bar",
          "binding": "/tabs"
        }
      ]
    },
    {
      "id": "wheel-page",
      "surfaceId": "wheel",
      "pageId": "wheel-page",
      "name": "随机转盘",
      "route": "pages/Wheel",
      "tabId": "tab-wheel",
      "semanticTargets": [
        {
          "id": "wheel-title",
          "role": "assertion"
        },
        {
          "id": "wheel-canvas",
          "role": "assertion",
          "binding": "/wheel/visual"
        },
        {
          "id": "wheel-candidate-list",
          "role": "list",
          "binding": "/wheel/candidates",
          "itemIdPattern": "wheel-candidate-{id}",
          "emptyStateId": "wheel-empty-state"
        },
        {
          "id": "wheel-add-candidate-input",
          "role": "input",
          "event": "wheel-add-candidate"
        },
        {
          "id": "wheel-add-candidate-button",
          "role": "action",
          "event": "wheel-add-candidate"
        },
        {
          "id": "wheel-spin-button",
          "role": "action",
          "event": "wheel-spin"
        },
        {
          "id": "wheel-result-label",
          "role": "assertion",
          "binding": "/wheel/result"
        },
        {
          "id": "wheel-share-result-button",
          "role": "action",
          "event": "open-share-sheet"
        },
        {
          "id": "wheel-remove-candidate-button",
          "role": "destructive-action",
          "event": "wheel-remove-candidate"
        },
        {
          "id": "wheel-tab-bar",
          "role": "tab-bar",
          "binding": "/tabs"
        }
      ]
    },
    {
      "id": "pantry-page",
      "surfaceId": "pantry",
      "pageId": "pantry-page",
      "name": "冰箱食材推荐",
      "route": "pages/Pantry",
      "tabId": "tab-pantry",
      "semanticTargets": [
        {
          "id": "pantry-title",
          "role": "assertion"
        },
        {
          "id": "pantry-ingredient-input",
          "role": "input",
          "event": "pantry-add-ingredient"
        },
        {
          "id": "pantry-add-ingredient-button",
          "role": "action",
          "event": "pantry-add-ingredient"
        },
        {
          "id": "pantry-ingredient-list",
          "role": "list",
          "binding": "/pantry/ingredients",
          "itemIdPattern": "pantry-ingredient-{id}",
          "emptyStateId": "pantry-empty-state"
        },
        {
          "id": "pantry-match-mode-toggle",
          "role": "input",
          "event": "pantry-toggle-match-mode",
          "binding": "/pantry/matchMode"
        },
        {
          "id": "pantry-recommend-button",
          "role": "action",
          "event": "pantry-recommend"
        },
        {
          "id": "pantry-recommendation-list",
          "role": "list",
          "binding": "/pantry/recommendations",
          "itemIdPattern": "pantry-recommendation-{id}",
          "emptyStateId": "pantry-no-recommendation-state"
        },
        {
          "id": "pantry-tab-bar",
          "role": "tab-bar",
          "binding": "/tabs"
        }
      ]
    },
    {
      "id": "filter-page",
      "surfaceId": "filter",
      "pageId": "filter-page",
      "name": "按心情/时间筛选",
      "route": "pages/Filter",
      "tabId": "tab-filter",
      "semanticTargets": [
        {
          "id": "filter-title",
          "role": "assertion"
        },
        {
          "id": "filter-mood-options",
          "role": "input",
          "event": "filter-select-mood",
