12	      background: #FFFDF7;
13	      color: #2E2720;
14	    }
15	    .app-shell {
16	      max-width: 420px;
17	      margin: 0 auto;
18	      min-height: 100%;
19	      position: relative;
20	      padding-bottom: 90px;
21	      background:
22	        radial-gradient(ellipse 90% 55% at 50% 0%, rgba(242,166,90,0.18), transparent 55%),
23	        radial-gradient(ellipse 80% 40% at 50% 100%, rgba(231,107,78,0.06), transparent 50%),
24	        #FFFDF7;
25	    }
26	    header { padding: 56px 20px 16px; display: flex; align-items: center; gap: 12px; }
27	    .back-btn {
28	      width: 40px; height: 40px; border-radius: 50%;
29	      background: #F7F1E8; display: flex; align-items: center; justify-content: center;
30	    }
31	    .back-btn svg { width: 22px; height: 22px; stroke: #2E2720; }
32	    .page-title { font-size: 30px; font-weight: 700; line-height: 1.22; letter-spacing: -0.4px; }
33	    .content { padding: 0 20px 24px; }
34	    .wheel-stage {
35	      display: flex; flex-direction: column; align-items: center;
36	      margin-top: 12px;
37	    }
