39	    .wheel-svg { width: 100%; height: 100%; transform: rotate(0deg); transition: transform 4s cubic-bezier(0.22, 1, 0.36, 1); }
40	    .wheel-center {
41	      position: absolute; top: 50%; left: 50%;
42	      width: 64px; height: 64px;
43	      transform: translate(-50%, -50%);
44	      background: #fff;
45	      border-radius: 50%;
