{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "dataModel": {
    "enums": {
      "MealTime": ["breakfast", "lunch", "dinner", "lateNight"],
      "Mood": ["healthy", "indulgent", "quick", "healing", "romantic"],
      "MatchMode": ["all", "any"]
    },
    "entities": {
      "Dish": {
        "id": "string",
        "name": "string",
        "ingredients": "string[]",
        "tags": "string[]",
        "moods": "Mood[]",
        "mealTimes": "MealTime[]"
      },
      "LogEntry": {
        "id": "string",
        "dishName": "string",
        "mealTime": "MealTime",
        "date": "string (YYYY-MM-DD)"
      }
    },
    "appState": {
      "/greeting": "string (time-of-day greeting)",
      "/today/recommendation": "Dish | null",
      "/wheel/candidates": "string[] (dish names)",
      "/wheel/result": "string | null",
      "/wheel/visual": "{ rotation: number, spinning: boolean }",
      "/pantry/ingredients": "string[]",
      "/pantry/matchMode": "'all' | 'any'",
      "/pantry/recommendations": "Dish[]",
      "/filter/mood": "Mood | null",
      "/filter/mealTime": "MealTime | null",
      "/filter/results": "Dish[]",
      "/log/date": "string (YYYY-MM-DD)",
      "/log/entries": "LogEntry[]",
      "/log/add/mealTime": "MealTime",
      "/share/card": "{ title, subtitle, contentLines, theme }",
      "/share/template": "string"
    },
    "persistence": {
      "store": "preferences (eat-what)",
      "keys": {
        "wheel_candidates": "string[]",
        "pantry_ingredients": "string[]",
        "pantry_match_mode": "'all' | 'any'",
        "log_entries": "LogEntry[]"
      },
      "seedPolicy": "starter DishLibrary seeded so pantry/filter/wheel are usable; spec marks HTML sample data as visual-only, but an empty app cannot satisfy pantry/filter acceptance criteria, so a small editable starter library is seeded."
    }
  },
  "services": {
    "StorageService": {
      "responsibility": "load/save wheel candidates, pantry ingredients, match mode, log entries via preferences",
      "api": ["loadCandidates", "saveCandidates", "loadIngredients", "saveIngredients", "loadMatchMode", "saveMatchMode", "loadLogs", "saveLogs"]
    },
    "DishLibrary": {
      "responsibility": "starter dishes + recommend(ingredients, mode) + filter(mood, mealTime) + pickRandomRecommendation()",
      "api": ["all", "recommend", "filter", "randomFor"]
    },
    "DateUtil": {
      "responsibility": "format YYYY-MM-DD, shift days, weekday/label, time-of-day greeting"
    }
  },
  "stateMachine": {
    "wheel": {
      "states": ["idle", "spinning", "result"],
      "transitions": [
        { "from": "idle|result", "event": "wheel-spin", "to": "spinning", "effect": "animate rotation 4s, pick random candidate, set result" },
        { "from": "spinning", "event": "animation-done", "to": "result", "effect": "show result sheet" }
      ]
    },
    "share": {
      "states": ["closed", "open"],
      "transitions": [
        { "event": "open-share-sheet", "to": "open", "effect": "set share payload from caller (wheel result | log day)" },
        { "event": "share-close", "to": "closed" }
      ]
    },
    "logAdd": {
      "states": ["hidden", "visible"],
      "transitions": [
        { "event": "log-open-add-sheet", "to": "visible" },
        { "event": "log-cancel-add|log-save-entry", "to": "hidden" }
      ]
    }
  },
  "interactionFlows": [
    {
      "id": "home-navigate",
      "trigger": "tap home-wheel-card | home-pantry-card | home-filter-card | home-log-card",
      "effect": "switch active tab to wheel|pantry|filter|log"
    },
    {
      "id": "wheel-spin",
      "trigger": "tap wheel-spin-button",
      "guard": "candidates.length >= 2",
      "steps": ["disable button", "animate rotation by random offset", "on done pick result candidate", "show result sheet", "enable share"],
      "errorPath": "candidates < 2 -> toast '至少添加2个候选'"
    },
    {
      "id": "wheel-add-candidate",
      "trigger": "tap wheel-add-candidate-button or submit wheel-add-candidate-input",
      "steps": ["read input", "trim", "dedupe", "persist", "clear input"],
      "errorPath": "empty or duplicate -> no-op"
    },
    {
      "id": "wheel-remove-candidate",
      "trigger": "tap remove on candidate chip",
      "steps": ["remove by index", "persist"]
    },
    {
      "id": "pantry-add-ingredient",
      "trigger": "tap pantry-add-ingredient-button or submit pantry-ingredient-input",
      "steps": ["trim", "dedupe", "persist", "clear input", "recompute recommendations"]
    },
    {
      "id": "pantry-toggle-match-mode",
      "trigger": "tap segmented control",
      "steps": ["switch all<->any", "persist", "recompute recommendations"]
    },
    {
      "id": "pantry-recommend",
      "trigger": "tap pantry-recommend-button",
      "steps": ["compute DishLibrary.recommend(ingredients, mode)", "render list / empty state"]
    },
    {
      "id": "filter-apply",
      "trigger": "tap filter-apply-button",
      "steps": ["compute DishLibrary.filter(mood, mealTime)", "render result list / empty state"]
    },
    {
      "id": "filter-spin-from-result",
      "trigger": "tap filter-spin-from-result-button",
      "guard": "results.length > 0",
      "effect": "pick random result, open share sheet with it"
    },
    {
      "id": "log-change-date",
      "trigger": "tap left/right arrow on log-date-selector",
      "steps": ["shift date by -1/+1 day", "reload entries for that date"]
    },
    {
      "id": "log-save-entry",
      "trigger": "tap log-add-save-button",
      "steps": ["read dish name + selected meal time", "append LogEntry for current date", "persist", "close sheet"],
      "errorPath": "empty dish name -> no-op"
    },
    {
      "id": "log-delete-entry",
      "trigger": "tap log-delete-entry-button",
      "steps": ["remove entry by id", "persist"]
    },
    {
      "id": "share-save-image",
      "trigger": "tap share-save-button",
      "effect": "save current card preview as image to album (component snapshot), toast feedback"
    },
    {
      "id": "share-system",
      "trigger": "tap share-system-button",
      "effect": "invoke system share panel with card text"
    }
  ],
  "testTargets": [
    "home-wheel-card", "home-pantry-card", "home-filter-card", "home-log-card",
    "wheel-spin-button", "wheel-add-candidate-input", "wheel-add-candidate-button",
    "wheel-candidate-list", "wheel-result-label", "wheel-share-result-button",
    "pantry-ingredient-input", "pantry-add-ingredient-button", "pantry-recommend-button",
