// Date helpers for the 今天吃什么 app.
// ArkTS-compatible: no Date.now()/new Date() side effects in pure helpers
// except where the page passes an explicit anchor date.

export class DateUtil {
  // Format a Date as YYYY-MM-DD (local).
  static toKey(d: Date): string {
    const y: number = d.getFullYear();
    const m: number = d.getMonth() + 1;
    const day: number = d.getDate();
    const mm: string = m < 10 ? `0${m}` : `${m}`;
    const dd: string = day < 10 ? `0${day}` : `${day}`;
    return `${y}-${mm}-${dd}`;
  }

  static todayKey(): string {
    return DateUtil.toKey(new Date());
  }

  static fromKey(key: string): Date {
    const parts: string[] = key.split('-');
    if (parts.length !== 3) {
      return new Date();
    }
    return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
  }

  // Shift a YYYY-MM-DD key by deltaDays.
  static shiftKey(key: string, deltaDays: number): string {
    const d: Date = DateUtil.fromKey(key);
    d.setDate(d.getDate() + deltaDays);
    return DateUtil.toKey(d);
  }

  static isSameDay(a: string, b: string): boolean {
    return a === b;
  }

  static weekdayLabel(d: Date): string {
    const names: string[] = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    return names[d.getDay()];
  }

  // "6月18日 周三"
  static prettyLabel(key: string): string {
    const d: Date = DateUtil.fromKey(key);
    return `${d.getMonth() + 1}月${d.getDate()}日 ${DateUtil.weekdayLabel(d)}`;
  }

  static relativeHint(key: string, todayKey: string): string {
    if (key === todayKey) {
      return '今天';
    }
    if (DateUtil.shiftKey(todayKey, -1) === key) {
      return '昨天';
    }
    if (DateUtil.shiftKey(todayKey, 1) === key) {
      return '明天';
    }
    return '';
  }

  // "2026.06.18"
  static dotLabel(key: string): string {
    return key.replace(/-/g, '.');
  }

  // Time-of-day greeting for the home header.
  static greetingFor(date: Date): string {
    const h: number = date.getHours();
    if (h < 5) {
      return '夜深了，来点夜宵？';
    } else if (h < 11) {
      return '早安，今天吃点什么？';
    } else if (h < 14) {
      return '午安，午饭想好了吗？';
    } else if (h < 18) {
      return '下午好，准备点心的了吗？';
    } else if (h < 22) {
      return '晚上好，今晚吃点啥？';
    }
    return '夜宵时间到啦！';
  }
}

