export class DishLibrary {
  static all(): Dish[] {
    return STARTER_DISHES;
  }

  static byId(id: string): Dish | null {
    for (const d of STARTER_DISHES) {
      if (d.id === id) {
        return d;
      }
    }
    return null;
  }

  static byName(name: string): Dish | null {
    for (const d of STARTER_DISHES) {
      if (d.name === name) {
        return d;
      }
    }
    return null;
  }

  // Returns dishes that use the user's ingredients.
  // mode 'all' = dish contains ALL user ingredients; 'any' = at least one.
  // Sorted by match strength (more matched ingredients first).
  static recommend(ingredients: string[], mode: MatchMode): Dish[] {
    const cleaned: string[] = ingredients
      .map((s: string) => s.trim())
      .filter((s: string) => s.length > 0);
    if (cleaned.length === 0) {
      return [];
    }
    const lower: string[] = cleaned.map((s: string) => s.toLowerCase());

    const scored: Array<{ dish: Dish; matched: number; ok: boolean }> = [];
    for (const dish of STARTER_DISHES) {
      const dishIng: string[] = dish.ingredients.map((s: string) => s.toLowerCase());
      let matched: number = 0;
      for (const need of lower) {
        for (const have of dishIng) {
          if (have.indexOf(need) >= 0 || need.indexOf(have) >= 0) {
            matched++;
            break;
          }
        }
      }
      const ok: boolean = mode === 'all' ? matched >= lower.length : matched > 0;
      scored.push({ dish, matched, ok });
    }
    const passed: Array<{ dish: Dish; matched: number }> = scored
      .filter((s) => s.ok)
      .map((s) => ({ dish: s.dish, matched: s.matched }));
    passed.sort((a, b) => b.matched - a.matched);
    return passed.map((s) => s.dish);
  }

  // Returns count of user ingredients that a dish contains (for match badge).
  static matchCount(dish: Dish, ingredients: string[]): number {
    const lower: string[] = ingredients
      .map((s: string) => s.trim().toLowerCase())
      .filter((s: string) => s.length > 0);
    const dishIng: string[] = dish.ingredients.map((s: string) => s.toLowerCase());
    let matched: number = 0;
    for (const need of lower) {
      for (const have of dishIng) {
        if (have.indexOf(need) >= 0 || need.indexOf(have) >= 0) {
          matched++;
          break;
        }
      }
    }
    return matched;
  }

  static isFullMatch(dish: Dish, ingredients: string[]): boolean {
    const cleaned: string[] = ingredients
      .map((s: string) => s.trim())
      .filter((s: string) => s.length > 0);
    return DishLibrary.matchCount(dish, cleaned) >= cleaned.length && cleaned.length > 0;
  }

  static filter(mood: Mood | null, mealTime: MealTime | null): Dish[] {
    const out: Dish[] = [];
    for (const d of STARTER_DISHES) {
      const moodOk: boolean = mood === null || d.moods.indexOf(mood) >= 0;
      const mealOk: boolean = mealTime === null || d.mealTimes.indexOf(mealTime) >= 0;
      if (moodOk && mealOk) {
        out.push(d);
      }
    }
    return out;
  }

  static randomFor(mood: Mood | null, mealTime: MealTime | null): Dish | null {
    const pool: Dish[] = DishLibrary.filter(mood, mealTime);
    if (pool.length === 0) {
      return null;
    }
    const idx: number = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }
}

