// Local persistence service backed by HarmonyOS preferences.
// Owns durability for wheel candidates, pantry ingredients, match mode,
// and daily log entries. Pages read/write through this service.

import { common } from '@kit.AbilityKit';
import { preferences } from '@kit.ArkData';
import { LogEntry, MatchMode } from '../model/Types';

const STORE_NAME: string = 'eat-what';
const KEY_CANDIDATES: string = 'wheel_candidates';
const KEY_INGREDIENTS: string = 'pantry_ingredients';
const KEY_MATCH_MODE: string = 'pantry_match_mode';
const KEY_LOGS: string = 'log_entries';

const DEFAULT_CANDIDATES: string[] = ['番茄鸡蛋', '红烧肉', '麻婆豆腐', '青菜面', '咖喱鸡饭', '清炒时蔬'];

export class StorageService {
  private static store: preferences.Preferences | null = null;

  static async init(context: common.Context): Promise<void> {
    if (StorageService.store !== null) {
      return;
    }
    StorageService.store = await preferences.getPreferences(context, STORE_NAME);
    await StorageService.store.flush();
  }

  private static pref(): preferences.Preferences {
    if (StorageService.store === null) {
      throw new Error('StorageService not initialized');
    }
    return StorageService.store;
  }

  // ---- wheel candidates ----
  static async getCandidates(): Promise<string[]> {
    const raw: preferences.ValueType = await StorageService.pref().get(KEY_CANDIDATES, '');
    return StorageService.parseStringArray(raw, DEFAULT_CANDIDATES);
  }

  static async setCandidates(list: string[]): Promise<void> {
    await StorageService.pref().put(KEY_CANDIDATES, JSON.stringify(list));
    await StorageService.pref().flush();
  }

  // ---- pantry ingredients ----
  static async getIngredients(): Promise<string[]> {
    const raw: preferences.ValueType = await StorageService.pref().get(KEY_INGREDIENTS, '');
    return StorageService.parseStringArray(raw, []);
  }

  static async setIngredients(list: string[]): Promise<void> {
    await StorageService.pref().put(KEY_INGREDIENTS, JSON.stringify(list));
    await StorageService.pref().flush();
  }

  // ---- match mode ----
  static async getMatchMode(): Promise<MatchMode> {
    const raw: preferences.ValueType = await StorageService.pref().get(KEY_MATCH_MODE, 'all');
    const v: string = `${raw}`;
    return v === 'any' ? 'any' : 'all';
  }

  static async setMatchMode(mode: MatchMode): Promise<void> {
    await StorageService.pref().put(KEY_MATCH_MODE, mode);
    await StorageService.pref().flush();
  }

  // ---- log entries ----
  static async getLogs(): Promise<LogEntry[]> {
    const raw: preferences.ValueType = await StorageService.pref().get(KEY_LOGS, '');
    return StorageService.parseLogArray(raw);
  }

  static async setLogs(list: LogEntry[]): Promise<void> {
    await StorageService.pref().put(KEY_LOGS, JSON.stringify(list));
    await StorageService.pref().flush();
  }

  // ---- parsing helpers ----
  private static parseStringArray(raw: preferences.ValueType, fallback: string[]): string[] {
    if (typeof raw !== 'string' || raw.length === 0) {
      return fallback;
    }
    try {
      const parsed: object = JSON.parse(raw);
      if (!Array.isArray(parsed)) {
        return fallback;
      }
      const out: string[] = [];
      const arr: object[] = parsed as object[];
      for (const item of arr) {
        if (typeof item === 'string') {
          out.push(item);
        }
      }
      return out.length > 0 ? out : fallback;
    } catch (e) {
      return fallback;
    }
  }

  private static parseLogArray(raw: preferences.ValueType): LogEntry[] {
    if (typeof raw !== 'string' || raw.length === 0) {
      return [];
    }
    try {
      const parsed: object = JSON.parse(raw);
      if (!Array.isArray(parsed)) {
        return [];
      }
      const out: LogEntry[] = [];
      const arr: object[] = parsed as object[];
      for (const item of arr) {
        const rec = item as Record<string, Object>;
        const id: Object | undefined = rec['id'];
        const dishName: Object | undefined = rec['dishName'];
        const mealTime: Object | undefined = rec['mealTime'];
        const date: Object | undefined = rec['date'];
        if (typeof id === 'string' && typeof dishName === 'string' &&
          typeof mealTime === 'string' && typeof date === 'string') {
          out.push({
            id: id,
            dishName: dishName,
            mealTime: mealTime as LogEntry['mealTime'],
            date: date,
          });
        }
      }
      return out;
    } catch (e) {
      return [];
    }
  }
}

