// Shared icon wrapper for 今天吃什么.
// Maps semantic variants to prepared rawfile SVG assets extracted from the
// HTML design (see rawfile/svg-style-manifest.json).
//
// SVG gate: all manifest icons are stroke-mode with empty fill_color, so we
// NEVER chain .fillColor() on these Images. Active/inactive states are
// rendered by switching to the prepared colored rawfile variant, not by tinting.
// `color` and `strokeWidth` stay on the public API for contract stability but
// are not applied (the prepared SVGs bake in the design color per context).

@Component
export struct SvgIcon {
  @Prop iconSize: number = 24;
  @Prop color: string = '#2E2720';
  @Prop strokeWidth: number = 2;
  @Prop variant: string = 'back';

  build() {
    Image($rawfile(this.fileNameForVariant()))
      .width(this.iconSize)
      .height(this.iconSize)
      .objectFit(ImageFit.Contain)
      .draggable(false)
  }

  private fileNameForVariant(): string {
    const v: string = this.variant;
    // tab bar (inactive / active colored variants)
    if (v === 'home') {
      return 'icon_切换到首页-1.svg';
    } else if (v === 'homeOn') {
      return 'icon_切换到首页-2.svg';
    } else if (v === 'wheel') {
      return 'icon_切换到随机转盘-1.svg';
    } else if (v === 'wheelOn') {
      return 'icon_切换到随机转盘-2.svg';
    } else if (v === 'pantry') {
      return 'icon_切换到冰箱食材推荐-1.svg';
    } else if (v === 'pantryOn') {
      return 'icon_切换到冰箱食材推荐-2.svg';
    } else if (v === 'filter') {
      return 'icon_切换到心情筛选-2.svg';
    } else if (v === 'filterOn') {
      return 'icon_切换到心情筛选-1.svg';
    } else if (v === 'log') {
      return 'icon_切换到饮食打卡-1.svg';
    } else if (v === 'logOn') {
      return 'icon_切换到饮食打卡-2.svg';
    }
    // navigation / actions
    if (v === 'back') {
      return 'icon_返回上一页.svg';
    } else if (v === 'addCandidate') {
      return 'icon_添加候选菜品.svg';
    } else if (v === 'addIngredient') {
      return 'icon_添加食材.svg';
    } else if (v === 'removeCandidate') {
      return 'icon_删除该候选菜品.svg';
    } else if (v === 'removeIngredient') {
      return 'icon_删除该食材.svg';
    } else if (v === 'deleteLog') {
      return 'icon_删除该打卡记录.svg';
    } else if (v === 'spin') {
      return 'icon_开始转盘随机选菜.svg';
    } else if (v === 'shareResult') {
      return 'icon_分享转盘结果.svg';
    } else if (v === 'shareDay') {
      return 'icon_分享今日打卡.svg';
    } else if (v === 'shareSystem') {
      return 'icon_调用系统分享卡片.svg';
    } else if (v === 'saveImage') {
      return 'icon_保存分享卡片到相册.svg';
    } else if (v === 'closeShare') {
      return 'icon_关闭分享面板.svg';
    } else if (v === 'datePrev') {
      return 'icon_切换到前一天.svg';
    } else if (v === 'dateNext') {
      return 'icon_切换到后一天.svg';
    } else if (v === 'fabAdd') {
      return 'icon_添加今日饮食打卡.svg';
    } else if (v === 'spinFromResult') {
      return 'icon_用筛选结果去转盘.svg';
    }
    // home quick entries
    if (v === 'quickWheel') {
      return 'icon_进入随机转盘.svg';
    } else if (v === 'quickPantry') {
      return 'icon_按冰箱食材推荐菜品.svg';
    } else if (v === 'quickFilter') {
      return 'icon_按心情和时间筛选菜品.svg';
    } else if (v === 'quickLog') {
      return 'icon_打开每日饮食打卡记录.svg';
    }
    // moods
    if (v === 'moodHealthy') {
      return 'icon_选择健康饮食心情.svg';
    } else if (v === 'moodIndulgent') {
      return 'icon_选择放纵饮食心情.svg';
    } else if (v === 'moodQuick') {
      return 'icon_选择快手饮食心情.svg';
    } else if (v === 'moodHealing') {
      return 'icon_选择治愈饮食心情.svg';
    } else if (v === 'moodRomantic') {
      return 'icon_选择浪漫饮食心情.svg';
    }
    // meal times
    if (v === 'mealBreakfast') {
      return 'icon_选择早餐时段.svg';
    } else if (v === 'mealLunch') {
      return 'icon_选择午餐时段.svg';
    } else if (v === 'mealDinner') {
      return 'icon_选择晚餐时段.svg';
    } else if (v === 'mealLateNight') {
      return 'icon_选择夜宵时段.svg';
    }
    // log entry icons (only breakfast/lunch exist; reuse for others)
    if (v === 'logBreakfast' || v === 'logLateNight') {
      return 'icon_早餐打卡图标.svg';
    } else if (v === 'logLunch' || v === 'logDinner') {
      return 'icon_午餐打卡图标.svg';
    }
    // dish placeholder icons
    if (v === 'dishHealthy') {
      return 'icon_健康菜品图标.svg';
    } else if (v === 'dishFresh') {
      return 'icon_清爽菜品图标.svg';
    }
    return 'icon_返回上一页.svg';
  }
}

