// Fixed bottom tab bar for 今天吃什么 — 5 primary tabs.
// Public API stays stable: activeTab + onTap.

import { SvgIcon } from '../common/SvgIcon';
import { TabId } from '../common/TabTypes';
import { Theme } from '../common/Theme';

interface TabDescriptor {
  id: TabId;
  label: string;
  icon: string;     // inactive variant
  iconOn: string;   // active colored variant
}

const TABS: TabDescriptor[] = [
  { id: 'tab-home', label: '首页', icon: 'home', iconOn: 'homeOn' },
  { id: 'tab-wheel', label: '转盘', icon: 'wheel', iconOn: 'wheelOn' },
  { id: 'tab-pantry', label: '食材', icon: 'pantry', iconOn: 'pantryOn' },
  { id: 'tab-filter', label: '筛选', icon: 'filter', iconOn: 'filterOn' },
  { id: 'tab-log', label: '打卡', icon: 'log', iconOn: 'logOn' },
];

@Component
export struct BottomTabBar {
  @Prop activeTab: TabId;
  onTap: (tab: TabId) => void = () => {};

  build() {
    Row() {
      ForEach(TABS, (tab: TabDescriptor) => {
        Column() {
          SvgIcon({
            variant: this.activeTab === tab.id ? tab.iconOn : tab.icon,
            iconSize: 24,
            color: this.activeTab === tab.id ? Theme.brandPrimary : Theme.textTertiary,
            strokeWidth: 2
          })
          Text(tab.label)
            .fontSize(11)
            .fontWeight(FontWeight.Bold)
            .fontColor(this.activeTab === tab.id ? Theme.brandPrimary : Theme.textTertiary)
            .margin({ top: 4 })
        }
        .id(tab.id)
        .padding({ left: 6, right: 6, top: 6, bottom: 6 })
        .onClick(() => this.onTap(tab.id))
        .layoutWeight(1)
        .alignItems(HorizontalAlign.Center)
        .justifyContent(FlexAlign.Center)
      }, (tab: TabDescriptor) => tab.id)
    }
    .width('100%')
    .height(Theme.bottomTabHeight)
    .padding({ bottom: 8 })
    .backgroundColor('rgba(255,253,247,0.94)')
    .backdropBlur(22)
    .border({ width: { top: 0.5 }, color: { top: Theme.borderSoft } })
    .justifyContent(FlexAlign.SpaceAround)
    .alignItems(VerticalAlign.Center)
  }
}

