// Decorative top radial glow layer matching the HTML design's
// radial-gradient halos. Tinted per page (warm/avocado/berry/mint).

@Component
export struct GlowBackground {
  @Prop tint: string = '#F2A65A';
  @Prop tintAlpha: number = 0.18;

  build() {
    Column()
      .width('100%')
      .height('100%')
      .linearGradient({
        angle: 180,
        direction: GradientDirection.Bottom,
        colors: [[this.tintColor(), 0.0], ['#00000000', 0.35]]
      })
      .hitTestBehavior(HitTestMode.None)
  }

  private tintColor(): string {
    const a: number = Math.round(this.tintAlpha * 255);
    const hex: string = a < 16 ? `0${a.toString(16)}` : a.toString(16);
    return `${this.tint}${hex}`;
  }
}

