// Share card bottom sheet. Renders a preview card from a ShareCardPayload,
// template selector, and save / system-share actions.
//
// Save-to-album and system-share panel are wired to real feedback (toast).
// Writing the rendered preview to the photo library / invoking the system
// share controller is documented as a deferred enhancement in the handoff
// (requires snapshot + photoAccessHelper / systemShare setup).

import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { ShareCardPayload } from '../model/Types';
import { DateUtil } from '../model/DateUtil';
import { promptAction } from '@kit.ArkUI';

interface TemplateOption {
  id: string;
  label: string;
  badge: string;
  gradient: LinearGradient | null;
  bg: string;
  badgeColor: string;
}

@Component
export struct ShareSheet {
  payload: ShareCardPayload = {
    title: '今天吃',
    subtitle: '',
    contentLines: [],
    theme: 'warm',
    template: 'result',
  };
  onClose: () => void = () => {};

  @State selectedTemplate: string = 'result';

  aboutToAppear(): void {
    this.selectedTemplate = this.payload.template.length > 0 ? this.payload.template : 'result';
  }

  build() {
    Stack({ alignContent: Alignment.Center }) {
      // overlay
      Column()
        .width('100%')
        .height('100%')
        .backgroundColor(Theme.overlayDim)
        .onClick(() => this.onClose())

      // sheet
      Column() {
        this.SheetHeader()
        this.PreviewCard()
        this.TemplateSelector()
        this.ActionRow()
      }
      .width('100%')
      .backgroundColor(Theme.pageBg)
      .borderRadius({ topLeft: 32, topRight: 32 })
      .padding({ left: 22, right: 22, top: 24, bottom: 34 })
      .shadow({ radius: 40, color: 'rgba(46,39,32,0.20)', offsetY: -8 })
    }
    .width('100%')
    .height('100%')
    .alignContent(Alignment.Bottom)
  }

  @Builder
  SheetHeader() {
    Row() {
      Text('分享卡片')
        .fontSize(24)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Blank()
      Row() {
        SvgIcon({ variant: 'closeShare', iconSize: 20, color: Theme.textPrimary, strokeWidth: 2 })
      }
      .width(40)
      .height(40)
      .borderRadius(20)
      .backgroundColor(Theme.surfaceSoft)
      .justifyContent(FlexAlign.Center)
      .alignItems(VerticalAlign.Center)
      .id('share-close-button')
      .onClick(() => this.onClose())
    }
    .width('100%')
    .alignItems(VerticalAlign.Center)
  }

  @Builder
  PreviewCard() {
    Column() {
      Column() {
        // decorative circles
        Column()
          .width(180)
          .height(180)
          .borderRadius(90)
          .backgroundColor('rgba(255,255,255,0.12)')
          .position({ x: '62%', y: -60 })
        Column()
          .width(220)
          .height(220)
          .borderRadius(110)
          .backgroundColor('rgba(255,255,255,0.08)')
          .position({ x: -70, y: '70%' })

        Column() {
          Text(this.payload.title)
            .fontSize(15)
            .fontWeight(FontWeight.Medium)
            .fontColor('rgba(255,255,255,0.92)')
          Text(this.payload.contentLines.length > 0 ? this.payload.contentLines[0] : '')
            .fontSize(40)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
            .letterSpacing(-0.8)
            .margin({ top: 14 })
          if (this.payload.subtitle.length > 0) {
            Text(this.payload.subtitle)
              .fontSize(14)
              .fontColor('rgba(255,255,255,0.85)')
              .margin({ top: 12 })
          }
          Blank()
          Text('今天吃什么 · 轻松决定每一餐')
            .fontSize(13)
            .fontColor('rgba(255,255,255,0.7)')
        }
        .width('100%')
        .height('100%')
        .padding(28)
        .alignItems(HorizontalAlign.Start)
      }
      .width('100%')
      .aspectRatio(0.8)
      .borderRadius(24)
      .padding({ top: 30, bottom: 30 })
      .linearGradient(this.previewGradient())
      .clip(true)
      .shadow({ radius: 44, color: 'rgba(46,39,32,0.15)', offsetY: 18 })
    }
    .width('100%')
    .margin({ top: 18, bottom: 22 })
  }

  @Builder
  TemplateSelector() {
    Row({ space: 14 }) {
      ForEach(this.templates(), (t: TemplateOption) => {
        Column() {
          Column()
            .width(70)
            .height(70)
            .borderRadius(16)
            .border({
              width: this.selectedTemplate === t.id ? 2 : 0,
              color: Theme.brandPrimary
            })
            .linearGradient(t.gradient ?? BrandGradient.warm)
            .backgroundColor(t.bg)
            .justifyContent(FlexAlign.Center)
            .alignItems(HorizontalAlign.Center)
          Text(t.label)
            .fontSize(11)
            .fontColor(Theme.textTertiary)
            .margin({ top: 6 })
        }
        .onClick(() => {
          this.selectedTemplate = t.id;
        })
      }, (t: TemplateOption) => t.id)
    }
    .id('share-template-selector')
    .width('100%')
    .margin({ bottom: 24 })
  }

  @Builder
  ActionRow() {
    Row({ space: 12 }) {
      Row({ space: 8 }) {
        SvgIcon({ variant: 'saveImage', iconSize: 20, color: '#FFFFFF', strokeWidth: 2 })
        Text('保存图片')
          .fontSize(16)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
      }
      .layoutWeight(1)
      .height(54)
      .borderRadius(999)
      .justifyContent(FlexAlign.Center)
      .alignItems(VerticalAlign.Center)
      .linearGradient(BrandGradient.warm)
      .id('share-save-button')
      .onClick(() => {
        promptAction.showToast({ message: '已保存到相册（预览）', duration: 2000 });
      })

      Row({ space: 8 }) {
        SvgIcon({ variant: 'shareSystem', iconSize: 20, color: Theme.textPrimary, strokeWidth: 2 })
        Text('更多分享')
          .fontSize(16)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
      }
      .layoutWeight(1)
      .height(54)
      .borderRadius(999)
      .justifyContent(FlexAlign.Center)
      .alignItems(VerticalAlign.Center)
      .backgroundColor(Theme.surfaceSoft)
      .id('share-system-button')
      .onClick(() => {
        promptAction.showToast({ message: '已调用系统分享（预览）', duration: 2000 });
      })
    }
    .width('100%')
  }

  private previewGradient(): LinearGradient {
    if (this.selectedTemplate === 'result') {
      return BrandGradient.warm;
    }
    return {
      angle: 135,
      direction: GradientDirection.RightTop,
      colors: [['#68C6C3', 0.0], ['#4AB0AD', 1.0]],
    } as LinearGradient;
  }

  private templates(): TemplateOption[] {
    return [
      { id: 'result', label: '结果', badge: '转盘', gradient: BrandGradient.warm, bg: '#F2A65A', badgeColor: '#FFFFFF' },
      { id: 'diet', label: '饮食', gradient: null, bg: Theme.surfaceSoftAlt, badgeColor: Theme.textPrimary },
    ] as TemplateOption[];
  }
}

